export const setStyle = (
  element: HTMLElement,
  styleName: CSSProperties | keyof CSSProperties,
  value?: string | number
) => {
  if (!element || !styleName) return

  if (isObject(styleName)) {
    entriesOf(styleName).forEach(([prop, value]) =>
      setStyle(element, prop, value)
    )
  } else {
    const key: any = camelize(styleName)
    element.style[key] = value as any
  }
}

export const removeStyle = (
  element: HTMLElement,
  style: CSSProperties | keyof CSSProperties
) => {
  if (!element || !style) return

  if (isObject(style)) {
    keysOf(style).forEach((prop) => removeStyle(element, prop))
  } else {
    setStyle(element, style, '')
  }
}

export function addUnit(value?: string | number, defaultUnit = 'px') {
  if (!value && value !== 0) return ''
  if (isNumber(value) || isStringNumber(value)) {
    return `${value}${defaultUnit}`
  } else if (isString(value)) {
    return value
  }
  debugWarn(SCOPE, 'binding value must be a string or number')
}

import type { Ref } from 'vue'
import { onBeforeMount, onBeforeUnmount, ref } from 'vue'
import { isBrowser } from '../env/is-browser'

const isComposingRef = ref(false)
function compositionStartHandler(): void {
  isComposingRef.value = true
}
function compositionEndHandler(): void {
  isComposingRef.value = false
}
let mountedCount = 0

export function useIsComposing(): Ref<boolean> {
  if (isBrowser) {
    onBeforeMount(() => {
      if (!mountedCount) {
        window.addEventListener('compositionstart', compositionStartHandler)
        window.addEventListener('compositionend', compositionEndHandler)
      }
      mountedCount++
    })
    onBeforeUnmount(() => {
      if (mountedCount <= 1) {
        window.removeEventListener('compositionstart', compositionStartHandler)
        window.removeEventListener('compositionend', compositionEndHandler)
        mountedCount = 0
      }
      else {
        mountedCount--
      }
    })
  }
  return isComposingRef
}

export function useInjectionCollection(
  injectionName: string | InjectionKey<unknown>,
  collectionKey: string,
  valueRef: Ref<any>
): void {
  const injection = inject<Record<any, any[]> | null>(injectionName, null)
  if (injection === null)
    return
  if (!(collectionKey in injection)) {
    injection[collectionKey] = []
  }
  injection[collectionKey].push(valueRef.value)
  watch(valueRef, (value, prevValue) => {
    const collectionArray = injection[collectionKey]
    const index = collectionArray.findIndex(
      collectionValue => collectionValue === prevValue
    )
    if (~index)
      collectionArray.splice(index, 1)
    collectionArray.push(value)
  })
  onBeforeUnmount(() => {
    const collectionArray = injection[collectionKey]
    const index = collectionArray.findIndex(
      collectionValue => collectionValue === valueRef.value
    )
    if (~index)
      collectionArray.splice(index, 1)
  })
}

focusHandler(event) {
  // If focus leaves modal content, bring it back
  const content = this.$refs.content
  const { target } = event
  if (
    this.noEnforceFocus ||
    !this.isTop ||
    !this.isVisible ||
    !content ||
    document === target ||
    contains(content, target) ||
    (this.computeIgnoreEnforceFocusSelector &&
      closest(this.computeIgnoreEnforceFocusSelector, target, true))
  ) {
    return
  }
  const tabables = getTabables(this.$refs.content)
  const bottomTrap = this.$refs['bottom-trap']
  const topTrap = this.$refs['top-trap']
  if (bottomTrap && target === bottomTrap) {
    // If user pressed TAB out of modal into our bottom trab trap element
    // Find the first tabable element in the modal content and focus it
    if (attemptFocus(tabables[0])) {
      // Focus was successful
      return
    }
  } else if (topTrap && target === topTrap) {
    // If user pressed CTRL-TAB out of modal and into our top tab trap element
    // Find the last tabable element in the modal content and focus it
    if (attemptFocus(tabables[tabables.length - 1])) {
      // Focus was successful
      return
    }
  }
  // Otherwise focus the modal content container
  attemptFocus(content, { preventScroll: true })
}

export function parseSlide(raw: string, options: SlidevParserOptions = {}): Omit<SourceSlideInfo, 'filepath' | 'index' | 'start' | 'contentStart' | 'end'> {
  const matterResult = matter(raw, options)
  let note: string | undefined
  const frontmatter = matterResult.data || {}
  let content = matterResult.content.trim()
  const revision = hash(raw.trim())

  const comments = Array.from(content.matchAll(/<!--([\s\S]*?)-->/g))
  if (comments.length) {
    const last = comments[comments.length - 1]
    if (last.index !== undefined && last.index + last[0].length >= content.length) {
      note = last[1].trim()
      content = content.slice(0, last.index).trim()
    }
  }

  let title
  let level
  if (frontmatter.title || frontmatter.name) {
    title = frontmatter.title || frontmatter.name
  }
  else {
    const match = content.match(RE_HEADING)
    title = match?.[2]?.trim()
    level = match?.[1]?.length
  }
  if (frontmatter.level)
    level = frontmatter.level || 1

  const images = extractImagesUsage(content, frontmatter)

  return {
    raw,
    title,
    level,
    revision,
    content,
    contentRaw: content,
    frontmatter,
    frontmatterStyle: matterResult.type,
    frontmatterDoc: matterResult.doc,
    frontmatterRaw: matterResult.raw,
    note,
    images,
  }
}

function addSub(link: Link) {
  link.dep.sc++
  if (link.sub.flags & EffectFlags.TRACKING) {
    const computed = link.dep.computed
    // computed getting its first subscriber
    // enable tracking + lazily subscribe to all its deps
    if (computed && !link.dep.subs) {
      computed.flags |= EffectFlags.TRACKING | EffectFlags.DIRTY
      for (let l = computed.deps; l; l = l.nextDep) {
        addSub(l)
      }
    }

    const currentTail = link.dep.subs
    if (currentTail !== link) {
      link.prevSub = currentTail
      if (currentTail) currentTail.nextSub = link
    }

    if (__DEV__ && link.dep.subsHead === undefined) {
      link.dep.subsHead = link
    }

    link.dep.subs = link
  }
}

