value => {
  const $anchor = document.createElement('a')
  $anchor.href = value

  // We need to add the anchor to the document to make sure the
  // `pathname` is correctly detected in any browser
  document.body.appendChild($anchor)

  const result = ['hash', 'host', 'hostname', 'pathname', 'port', 'protocol', 'search'].reduce(
    (result, prop) => {
      result[prop] = $anchor[prop] || null
      return result
    },
    {}
  )

  // Make sure to remove the anchor from document as soon as possible
  document.body.removeChild($anchor)

  // Normalize port
  if (!result.port && result.protocol) {
    if (result.protocol === 'https:') {
      result.port = '443'
    }
    if (result.protocol === 'http:') {
      result.port = '80'
    }
  }

  // Return early for browsers that resolved a non-existing `hostname` correctly
  if (result.hostname) {
    return result
  }

  // Handle relative URL's
  if (value.charAt(0) === '/') {
    return parseUrl(window.location.origin + value)
  }

  // Handle all other URL's
  let baseUrl = window.location.href
  baseUrl = baseUrl.substring(0, baseUrl.lastIndexOf('/'))

  return parseUrl(`${baseUrl}/${value}`)
}

import type { TextDocument } from 'vscode'
import { parse } from '@slidev/parser'
import { defineService, useDisposable, useEventEmitter, watch } from 'reactive-vscode'
import { FoldingRangeKind, languages } from 'vscode'
import { getProjectFromDoc } from '../composables/useProjectFromDoc'
import { projects } from '../projects'

export const useFoldings = defineService(() => {
  const emitter = useEventEmitter<void>()
  watch(projects, () => emitter.fire(), { deep: true })
  useDisposable(languages.registerFoldingRangeProvider(
    {
      scheme: 'file',
      language: 'markdown',
    },
    {
      onDidChangeFoldingRanges: emitter.event,
      async provideFoldingRanges(document: TextDocument) {
        if (!getProjectFromDoc(document))
          return // Not a slidev markdown file
        // Not using global slides data because it updates too late
        const md = await parse(document.getText(), document.uri.fsPath)
        return md?.slides.map(source => ({
          start: Math.max(0, source.frontmatterStyle === 'frontmatter' ? source.start : source.start - 1),
          end: source.end - 1,
          kind: FoldingRangeKind.Region,
        }))
      },
    },
  ))
})

export const getEventCode = (event: KeyboardEvent): string => {
  if (event.code && event.code !== 'Unidentified') return event.code
  // On android, event.code is always '' (see https://developer.mozilla.org/en-US/docs/Web/API/KeyboardEvent/code#browser_compatibility)
  const key = getEventKey(event)

  if (key) {
    if (Object.values(EVENT_CODE).includes(key)) return key

    switch (key) {
      case ' ':
        return EVENT_CODE.space
      default:
        return ''
    }
  }

  return ''
}

export const getEventKey = (event: KeyboardEvent): string => {
  let key = event.key && event.key !== 'Unidentified' ? event.key : ''

  // On Android, event.key and event.code may not be useful when entering characters or space
  // So here we directly get the last character of the input
  // **only takes effect in the keyup event**
  if (!key && event.type === 'keyup' && isAndroid()) {
    const target = event.target as HTMLInputElement
    key = target.value.charAt(target.selectionStart! - 1)
  }

  return key
}

import type { Slots, VNode } from 'vue'
import { warn } from '../naive'
import { flatten } from './flatten'

export function getFirstSlotVNode(
  slots: Slots,
  slotName = 'default',
  props: Unknown = undefined
): VNode | null {
  const slot = slots[slotName]
  if (!slot) {
    warn('getFirstSlotVNode', `slot[${slotName}] is empty`)
    return null
  }
  const slotContent = flatten(slot(props))
  // vue will normalize the slot, so slot must be an array
  if (slotContent.length === 1) {
    return slotContent[0]
  }
  else {
    warn('getFirstSlotVNode', `slot[${slotName}] should have exactly one child`)
    return null
  }
}

export function getFirstSlotVNodeWithTypedProps<T>(
  slotName: string,
  slot: ((props: T) => VNode[]) | undefined,
  props: T
): VNode | null {
  if (!slot) {
    return null
  }
  const slotContent = flatten(slot(props))
  // vue will normalize the slot, so slot must be an array
  if (slotContent.length === 1) {
    return slotContent[0]
  }
  else {
    warn('getFirstSlotVNode', `slot[${slotName}] should have exactly one child`)
    return null
  }
}

(row, ignoreFields, includeFields, fieldsObj = {}) => {
  // We first need to format the row based on the field configurations
  // This ensures that we add formatted values for keys that may not
  // exist in the row itself
  const formattedRow = keys(fieldsObj).reduce((result, key) => {
    const field = fieldsObj[key]
    const { filterByFormatted } = field
    const formatter = isFunction(filterByFormatted)
      ? /* istanbul ignore next */ filterByFormatted
      : filterByFormatted
        ? /* istanbul ignore next */ field.formatter
        : null

    if (isFunction(formatter)) {
      result[key] = formatter(row[key], key, row)
    }

    return result
  }, clone(row))

  // Determine the allowed keys:
  //   - Ignore special fields that start with `_`
  //   - Ignore fields in the `ignoreFields` array
  //   - Include only fields in the `includeFields` array
  const allowedKeys = keys(formattedRow).filter(
    key =>
      !IGNORED_FIELD_KEYS[key] &&
      !(isArray(ignoreFields) && ignoreFields.length > 0 && arrayIncludes(ignoreFields, key)) &&
      !(isArray(includeFields) && includeFields.length > 0 && !arrayIncludes(includeFields, key))
  )

  return pick(formattedRow, allowedKeys)
}

(
  defaults: BAppProps['defaults'] | Ref<BAppProps['defaults']>,
  mergeDefaults: BAppProps['mergeDefaults']
) => {
  // Inject existing defaults from parent (could be from plugins)
  const injectedDefaults = inject(defaultsKey, null)

  // Merge injected defaults with prop defaults (prop takes priority)
  const mergedDefaults = computed<Partial<BvnComponentProps>>(() => {
    const _defaults = unref(defaults)
    if (!injectedDefaults) {
      return _defaults ?? {}
    }
    const merged = {...injectedDefaults.value} as Partial<BvnComponentProps>

    if (_defaults) {
      // If mergeDefaults is a function, call it with
      if (mergeDefaults) {
        if (typeof mergeDefaults === 'function') {
          return mergeDefaults(merged, _defaults) as Partial<BvnComponentProps>
        } else if (mergeDefaults === true) {
          return deepMerge(merged, _defaults)
        }
        return Object.assign(merged, _defaults)
      }
      return _defaults
    }

    return merged
  })

  // Provide the merged defaults to child components
  provide(defaultsKey, mergedDefaults)
}

(el: ElementWithScrollspy, binding: Readonly<DirectiveBinding>) => {
  // SSR guard: skip on server
  const doc = getSafeDocument()
  if (doc === null) return

  const uid = getDirectiveUid(binding)

  // Initialize UID namespace for this directive
  const elWithScrollspy = el as ElementWithScrollspy & Record<string, unknown>
  elWithScrollspy.$__scrollspy = elWithScrollspy.$__scrollspy ?? Object.create(null)

  // Clean up existing instance if present
  const existingInstance = elWithScrollspy.$__scrollspy![uid]
  if (existingInstance) {
    existingInstance.cleanup()
  }

  const {arg, value} = binding
  const isObject = typeof value === 'object' && value !== null
  const content = arg
    ? arg
    : typeof value === 'string'
      ? value
      : isObject
        ? value.content || value.element
        : null

  // Store scrollspy instance for this component instance
  elWithScrollspy.$__scrollspy![uid] = useScrollspy(
    content,
    el,
    isObject ? omit(value, ['content', 'element']) : {}
  )
}

export function usePageNav() {
  const { page, theme } = useData()
  const lang = useLang()

  const candidates = computed(() => {
    const config = getSidebarConfig(
      theme.value.sidebars,
      page.value.relativePath,
      lang.value
    )
    return Array.isArray(config) ? getFlatSideBarLinks(config) : []
  })

  const index = computed(() => {
    return candidates.value.findIndex((item) => {
      return isActive(page.value.relativePath, item.link)
    })
  })
  const next = computed(() => {
    if (
      theme.value.nextLinks !== false &&
      index.value > -1 &&
      index.value < candidates.value.length - 1
    ) {
      return candidates.value[index.value + 1]
    }

    return null
  })

  const prev = computed(() => {
    if (theme.value.prevLinks !== false && index.value > 0) {
      return candidates.value[index.value - 1]
    }
    return null
  })

  const hasLinks = computed(() => !!next.value || !!prev.value)
  return {
    next,
    prev,
    hasLinks,
  }
}

beforeUnmount() {
    if (typeof window !== 'undefined') {
        document.removeEventListener('click', this.clickedOutside)
        if (this.dropdownPosition === 'auto') {
            window.removeEventListener(
                'resize',
                this.calcDropdownInViewportVertical
            )
        }
        if (this.appendToBody) {
            window.removeEventListener(
                'scroll',
                this.calcDropdownInViewportVertical
            )
        }
    }
    if (
        this.checkInfiniteScroll &&
        this.$refs.dropdown &&
        (this.$refs.dropdown as Element).querySelector('.dropdown-content')
    ) {
        const list = (this.$refs.dropdown as Element).querySelector(
            '.dropdown-content'
        )!
        list.removeEventListener(
            'scroll',
            this.checkIfReachedTheEndOfScroll
        )
    }
    if (this.appendToBody && this.$data._bodyEl) {
        removeElement(this.$data._bodyEl)
    }
    clearTimeout(this.timeOutID)
}

selectItem(value: ItemValueType) {
    if (this.multiple) {
        if (this.selected) {
            const selected = this.selected as ItemValueType[]
            if (selected.indexOf(value) === -1) {
                // Add value
                this.selected = [...selected, value]
            } else {
                // Remove value
                this.selected = selected.filter((val) => val !== value)
            }
        } else {
            this.selected = [value]
        }
        this.$emit('change', this.selected)
    } else {
        if (this.selected !== value) {
            this.selected = value
            this.$emit('change', this.selected)
        }
    }
    this.$emit('update:modelValue', this.selected)
    if (!this.multiple) {
        this.isActive = !this.closeOnClick
        if (this.hoverable && this.closeOnClick) {
            this.isHoverable = false
        }
    }
}

sort(
    column: ITableColumn | null | undefined,
    updatingData: boolean | null = false,
    event: ModifierKeys | null = null
) {
    if (!column || !column.sortable) return
    if (
        // if backend sorting is enabled, just emit the sort press like usual
        // if the correct key combination isnt pressed, sort like usual
        !this.backendSorting &&
        this.sortMultiple &&
        ((this.sortMultipleKey && event![this.sortMultipleKey]) || !this.sortMultipleKey)
    ) {
        if (updatingData) {
            this.doSortMultiColumn()
        } else {
            this.sortMultiColumn(column)
        }
    } else {
        // sort multiple is enabled but the correct key combination isnt pressed so reset
        if (this.sortMultiple) {
            this.sortMultipleDataLocal = []
        }

        if (!updatingData) {
            this.isAsc = toRaw(column) === toRaw(this.currentSortColumn)
                ? !this.isAsc
                : (this.defaultSortDirection.toLowerCase() !== 'desc')
        }
        if (!this.firstTimeSort) {
            this.$emit('sort', column.field, this.isAsc ? 'asc' : 'desc', event)
        }
        if (!this.backendSorting) {
            this.doSortSingleColumn(column)
        }
        this.currentSortColumn = column
    }
}

handleKeyDown(e) {
  const { target, keyCode } = e;

  switch (keyCode) {
    case KeyCode.up:
      const prev = getSibling(target, -1);
      focusNode(prev);
      break;
    case KeyCode.down:
      const next = getSibling(target, 1);
      focusNode(next);
      break;
    case KeyCode.left:
      const preMenu = this.$refs.menu[getMenuIndex(target) - 1];
      if (preMenu) {
        const expandedNode = preMenu.$el.querySelector('.el-cascader-node[aria-expanded="true"]');
        focusNode(expandedNode);
      }
      break;
    case KeyCode.right:
      const nextMenu = this.$refs.menu[getMenuIndex(target) + 1];
      if (nextMenu) {
        const firstNode = nextMenu.$el.querySelector('.el-cascader-node[tabindex="-1"]');
        focusNode(firstNode);
      }
      break;
    case KeyCode.enter:
      checkNode(target);
      break;
    case KeyCode.esc:
    case KeyCode.tab:
      this.$emit('close');
      break;
    default:
      return;
  }
}

() => {
  let scrollBarWidth = 0
  let withoutHiddenClass = false
  let bodyPaddingRight = '0'
  let computedBodyPaddingRight = 0

  onUnmounted(() => {
    cleanup()
  })

  const cleanup = () => {
    if (!isClient) return
    removeClass(document.body, 'el-popup-parent--hidden')
    if (withoutHiddenClass) {
      document.body.style.paddingRight = bodyPaddingRight
    }
  }

  const lock = () => {
    if (!isClient) return
    withoutHiddenClass = !hasClass(document.body, 'el-popup-parent--hidden')
    if (withoutHiddenClass) {
      bodyPaddingRight = document.body.style.paddingRight
      computedBodyPaddingRight = Number.parseInt(
        getStyle(document.body, 'paddingRight'),
        10
      )
    }
    scrollBarWidth = getScrollBarWidth(defaultNamespace)
    const bodyHasOverflow =
      document.documentElement.clientHeight < document.body.scrollHeight
    const bodyOverflowY = getStyle(document.body, 'overflowY')
    if (
      scrollBarWidth > 0 &&
      (bodyHasOverflow || bodyOverflowY === 'scroll') &&
      withoutHiddenClass
    ) {
      document.body.style.paddingRight = `${
        computedBodyPaddingRight + scrollBarWidth
      }px`
    }
    addClass(document.body, 'el-popup-parent--hidden')
  }

  return {
    lock,
    cleanup,
  }
}

(component: string) => {
  const count = ref<number | null>(null)
  const loading = ref(false)

  const fetchCount = async () => {
    const cached = cache.get(component)
    if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
      count.value = cached.count
      return
    }

    loading.value = true
    try {
      const q = encodeURIComponent(
        `repo:element-plus/element-plus is:open is:issue in:title [${component}]`
      )
      const res = await fetch(
        `https://api.github.com/search/issues?q=${q}&per_page=1`
      )
      if (res.ok) {
        const data = await res.json()
        const total = data.total_count ?? 0
        count.value = total
        cache.set(component, { count: total, timestamp: Date.now() })
      } else {
        count.value = 0
      }
    } catch {
      count.value = 0
    } finally {
      loading.value = false
    }
  }

  onMounted(() => {
    fetchCount()
  })

  return { count, loading }
}

() => {
  if (!scrollContainer.value) return

  scrollTop.value =
    scrollContainer.value instanceof Window
      ? document.documentElement.scrollTop
      : scrollContainer.value.scrollTop || 0

  const { position, target, offset } = props
  const rootHeightOffset = offset + rootHeight.value

  if (position === 'top') {
    if (target) {
      const difference = targetRect.bottom.value - rootHeightOffset
      fixed.value = offset > rootTop.value && targetRect.bottom.value > 0
      transform.value = difference < 0 ? difference : 0
    } else {
      fixed.value = offset > rootTop.value
    }
  } else if (target) {
    const difference =
      windowHeight.value - targetRect.top.value - rootHeightOffset
    fixed.value =
      windowHeight.value - offset < rootBottom.value &&
      windowHeight.value > targetRect.top.value
    transform.value = difference < 0 ? -difference : 0
  } else {
    fixed.value = windowHeight.value - offset < rootBottom.value
  }
}

(event: Readonly<Event>, stepper: (step: number) => void) => {
  const {type} = event || {}

  if (!props.disabled && !props.readonly) {
    if (isMouseEvent(event)) {
      // We only respond to left (main === 0) button clicks
      if (type === 'mousedown' && event.button) return
    }
    resetTimers()
    // Step the counter initially
    stepper(1)
    const threshold = computedThreshold.value
    const multiplier = computedStepMultiplier.value
    const delay = computedDelay.value
    const interval = computedInterval.value

    // Initiate the delay/repeat interval
    $_autoDelayTimer = setTimeout(() => {
      let count = 0
      $_autoRepeatTimer = setInterval(() => {
        // After N initial repeats, we increase the incrementing step amount
        // We do this to minimize screen reader announcements of the value
        // (values are announced every change, which can be chatty for SR users)
        // And to make it easer to select a value when the range is large
        stepper(count < threshold ? 1 : multiplier)
        count++
      }, interval)
    }, delay)
  }
}

